sqlMap.select:
select *, cc.abbr as compName from (
) t1 left join fnd_company cc on cc.id = t1.compId
limit 1

sqlMap.insert:

    INSERT INTO `pm_project_weekly`(`projectId`,`currentTask`,`taskStartTime`,`taskEndTime`,`taskDeviation`,`remark`,`createTime`,`createBy`,`weeklyStartTime`,`weeklyEndTime`,weeklyState)
    values(#projectId# ,#currentTask# ,#taskStartTime# ,#taskEndTime# ,#taskDeviation# ,#remark# ,#createTime# ,#createBy# ,#weeklyStartTime# ,#weeklyEndTime# ,#weeklyState#)

    
     SELECT last_insert_id() as id ;


    INSERT INTO pm_project_soft_change_logs(projectId ,changeVersion , changeRemark , latest,createBy , createTime)
    values(#softChangeLog.projectId# ,#softChangeLog.changeVersion# , #softChangeLog.changeRemark#,1,#createBy#,now() )


    SELECT last_insert_id() as id ;


    INSERT INTO `pm_project_log`(`projectId`,`handleName`,`handleDesc`,`handleUser`,`taskStartTime`,`handleState`)
    values(#projectId#, #handleName#, #handleDesc#, #handleUser#, now(), 0)

    
     SELECT last_insert_id() as id ;


    INSERT INTO `pm_project_notification`(`notifySubject`,`notifyContent`,`projectId`,`createBy`,`createTime`)
    values(#notifySubject# ,#notifyContent# , #projectId#,#createBy# ,now())

    
     SELECT last_insert_id() as id ;

sqlMap.select:
SELECT contractNo, itemCode, IF(itemModel = IFNULL(itemModel2, itemModel), itemModel, CONCAT(t.itemModel, '
(', itemModel2, ')')) AS itemModel, IF(itemName = IFNULL(itemName2, itemName), itemName, CONCAT(t.itemName, '
(', itemName2, ')')) AS itemName, t.qty, t.barCodes, t.warrantyEndTime FROM (SELECT contractNo, IF(t.itemCode2 IS NULL, t.itemCode, CONCAT(t.itemCode, '
(', itemCode2, ')')) AS itemCode, CASE WHEN fi.`itemname` IS NULL OR fi.itemname = '' OR fi.itemname = '/' THEN fi.describe_ ELSE fi.itemname END AS itemModel, CASE WHEN fi2.`itemname` IS NULL OR fi2.itemname = '' OR fi2.itemname = '/' THEN fi2.describe_ ELSE fi2.itemname END AS itemModel2, fi.describe_ AS itemName, fi2.describe_ AS itemName2, COUNT(1) AS qty, GROUP_CONCAT(DISTINCT IF(t.barCode2 IS NULL, t.barcode, CONCAT(t.barcode, '(', t.barCode2, ')')) ORDER BY t.barCode SEPARATOR '、' ) AS barCodes, MIN(vw.warrantyEndTime) AS warrantyEndTime FROM ( SELECT DISTINCT vsip.contract_code contractNo, vsip.barcode barCode, vsip.itemCode itemCode, -1 AS transferFlag, vsip.barcode2 barCode2, vsip.itemcode2 FROM view_shipment_info_4_pm vsip LEFT JOIN view_shipment_ems_4_pm vsep ON vsep.contract_code = vsip.contract_code AND vsep.packId = vsip.packId WHERE vsip.contract_code in ($contractNo$) AND NOT EXISTS(SELECT 1 FROM pm_project_shipment pps1 WHERE vsip.barcode = pps1.barcode and contractNo in ($contractNo$) and projectId = #projectId# ) vsip.profitCenter = #profitCenter# UNION ALL SELECT DISTINCT pps.`contractNo`, pps.`barcode`, pps.`itemCode`, pps.transferFlag, sbr.sn2 as barCode2, sbr.item2 FROM pm_project_shipment pps LEFT JOIN `fb_shipment_barcode_relation` sbr ON sbr.contract = REPLACE(pps.contractNo, '-C', '') AND pps.barcode = sbr.sn1 WHERE contractNo in ($contractNo$) AND projectId = #projectId# AND EXISTS (SELECT 1 FROM view_shipment_info_4_pm vsip LEFT JOIN view_shipment_ems_4_pm vsep ON vsep.contract_code = vsip.contract_code AND vsep.packId = vsip.packId WHERE vsip.contract_code in ($sourceContractNo$)
AND vsip.barcode = pps.barcode)
) t LEFT JOIN `fb_items` fi ON fi.`item` = t.itemCode LEFT JOIN `fb_items` fi2 ON fi2.`item` = t.itemCode2 LEFT JOIN `view_warranty` vw ON vw.contract_code in ($sourceContractNo$) AND vw.barcode = t.barcode WHERE t.transferFlag != 1 AND vw.warrantyEndTime IS NOT NULL GROUP BY t.itemCode, vw.warrantyEndTime) t ORDER BY t.contractNo, t.itemCode, warrantyEndTime, t.qty DESC;
